query:
{
  kmsVaults(
    where: {
      OR: [
        { loggingEnabled: { eq: false } }
        {
          diagnosticSettings_SOME: {
            resourceType: { eq: "Microsoft.KeyVault/vaults" }
            logs_SOME: {
              enabled: { eq: false }
              categoryGroup_IN: ["audit", "allLogs"]
            }
          }
        }
      ]
    }
  ) {
    ...AssetFragment
  }
}
